 52→      globalThis as typeof globalThis & {
 53→        chrome?: { runtime?: { getURL?: (assetPath: string) => string } };
 54→      }
 55→    ).chrome?.runtime;
 56→    const getUrl = runtime?.getURL ?? fallbackRuntime?.getURL;
